import { setup, assign, fromPromise } from 'xstate';

interface Ctx {
  blob: Blob | null;
  savedId: string | null;
  error: string | null;
}

type Ev =
  | { type: 'START' }
  | { type: 'STOP'; blob: Blob }
  | { type: 'KEEP' }
  | { type: 'DISCARD' };

const saveRecording = fromPromise<string, { blob: Blob }>(async ({ input }) => {
  const fd = new FormData();
  fd.append('video', input.blob);
  const res = await fetch('/api/videos', { method: 'POST', body: fd });
  if (!res.ok) throw new Error('upload failed');
  const body = (await res.json()) as { id: string };
  return body.id;
});

export const videoRecorderMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { saveRecording }
}).createMachine({
  id: 'videoRecorder',
  initial: 'idle',
  context: { blob: null, savedId: null, error: null },
  states: {
    idle: { on: { START: 'recording' } },
    recording: {
      on: {
        STOP: {
          target: 'preview',
          actions: assign({ blob: ({ event }) => event.blob })
        }
      }
    },
    preview: {
      on: {
        KEEP: 'saving',
        DISCARD: { target: 'idle', actions: assign({ blob: null }) }
      }
    },
    saving: {
      invoke: {
        src: 'saveRecording',
        input: ({ context }) => ({ blob: context.blob as Blob }),
        onDone: {
          target: 'idle',
          actions: assign({ savedId: ({ event }) => event.output, blob: null })
        },
        onError: {
          target: 'preview',
          actions: assign({ error: ({ event }) => String(event.error) })
        }
      }
    }
  }
});
