import { setup, assign } from 'xstate';

interface Ctx { elapsedMs: number; }
type Ev =
  | { type: 'START' }
  | { type: 'PAUSE' }
  | { type: 'RESUME' }
  | { type: 'STOP' }
  | { type: 'TICK'; delta: number };

export const videoTimerMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actions: {
    addDelta: assign({
      elapsedMs: ({ context, event }) => {
        if (event.type !== 'TICK') return context.elapsedMs;
        return context.elapsedMs + event.delta;
      }
    }),
    reset: assign({ elapsedMs: 0 })
  }
}).createMachine({
  id: 'videoTimer',
  initial: 'idle',
  context: { elapsedMs: 0 },
  states: {
    idle: { on: { START: { target: 'recording.active', actions: 'reset' } } },
    recording: {
      initial: 'active',
      on: { STOP: 'idle' },
      states: {
        active: {
          on: {
            PAUSE: 'paused',
            TICK: { actions: 'addDelta' }
          }
        },
        paused: { on: { RESUME: 'active' } }
      }
    }
  }
});
