import { setup, assign, fromCallback } from 'xstate';

type Point = { x: number; y: number };
interface Ctx { strokes: Point[][]; current: Point[]; }
type Ev =
  | { type: 'POINTER_DOWN'; point: Point }
  | { type: 'POINTER_MOVE'; point: Point }
  | { type: 'POINTER_UP' }
  | { type: 'COMPLETE' };

const pointerListener = fromCallback<Ev, { target: HTMLElement }>(({ sendBack, input }) => {
  const el = input.target;
  const onDown = (e: PointerEvent) => sendBack({ type: 'POINTER_DOWN', point: { x: e.offsetX, y: e.offsetY } });
  const onMove = (e: PointerEvent) => sendBack({ type: 'POINTER_MOVE', point: { x: e.offsetX, y: e.offsetY } });
  const onUp = () => sendBack({ type: 'POINTER_UP' });
  el.addEventListener('pointerdown', onDown);
  el.addEventListener('pointermove', onMove);
  el.addEventListener('pointerup', onUp);
  return () => {
    el.removeEventListener('pointerdown', onDown);
    el.removeEventListener('pointermove', onMove);
    el.removeEventListener('pointerup', onUp);
  };
});

export const canvasMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev, input: {} as { target: HTMLElement } },
  actors: { pointerListener }
}).createMachine({
  id: 'canvas',
  initial: 'idle',
  context: { strokes: [], current: [] },
  invoke: { src: 'pointerListener', input: ({ event }) => (event as { input: { target: HTMLElement } }).input },
  states: {
    idle: {
      on: {
        POINTER_DOWN: {
          target: 'drawing',
          actions: assign({ current: ({ event }) => [event.point] })
        },
        COMPLETE: 'complete'
      }
    },
    drawing: {
      on: {
        POINTER_MOVE: {
          actions: assign({ current: ({ context, event }) => [...context.current, event.point] })
        },
        POINTER_UP: {
          target: 'idle',
          actions: assign({
            strokes: ({ context }) => [...context.strokes, context.current],
            current: []
          })
        }
      }
    },
    complete: { type: 'final' }
  }
});
