import { setup, assign } from 'xstate';

type Point = { x: number; y: number };
interface Ctx { strokes: Point[][]; current: Point[] | null; }
type Ev =
  | { type: 'BEGIN'; point: Point }
  | { type: 'EXTEND'; point: Point }
  | { type: 'END' }
  | { type: 'UNDO' };

export const drawingMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actions: {
    startStroke: assign({
      current: ({ event }) => (event.type === 'BEGIN' ? [event.point] : null)
    }),
    extendStroke: assign({
      current: ({ context, event }) =>
        event.type === 'EXTEND' && context.current
          ? [...context.current, event.point]
          : context.current
    }),
    commitStroke: assign({
      strokes: ({ context }) =>
        context.current ? [...context.strokes, context.current] : context.strokes,
      current: null
    }),
    popStroke: assign({
      strokes: ({ context }) => context.strokes.slice(0, -1)
    })
  }
}).createMachine({
  id: 'drawing',
  initial: 'idle',
  context: { strokes: [], current: null },
  states: {
    idle: {
      on: {
        BEGIN: { target: 'drawing', actions: 'startStroke' },
        UNDO: { actions: 'popStroke' }
      }
    },
    drawing: {
      on: {
        EXTEND: { actions: 'extendStroke' },
        END: { target: 'idle', actions: 'commitStroke' }
      }
    }
  }
});
```

